class Data_Service {
    static ping = async (url)  => {
        const [biz_response,biz_data] = await Service.ping(url);
        return [biz_response,biz_data];
    }
    static count = async (url,search,option)  => {
        const [biz_response,biz_data] = await Service.search(url,search,option);
        return [biz_response,biz_data];
    }
    static copy = async (url,table,id,option)  => {
        const [biz_response,biz_data] = await Service.copy(url,table,id,option);
        return [biz_response,biz_data];
    }
    static delete = async (url,table,id,option)  => {
        const [biz_response,biz_data] = await Service.delete(url,table,id,option);
        return [biz_response,biz_data];
    }
    static delete_search = async (url,search,option)  => {
        const [biz_response,biz_data] = await Service.delete_search(url,search,option);
        return [biz_response,biz_data];
    }
    static get = async (url,table,id,option)  => {
        const [biz_response,biz_data] = await Service.get(url,table,id,option);
        return [biz_response,biz_data];
    }
    static post = async (url,table,id,post_data,option)  => {
        const [biz_response,biz_data] = await Service.post(url,table,id,post_data,option);
        return [biz_response,biz_data];
    }
    static post_items = async (url,items,option)  => {
        const [biz_response,biz_data] = await Service.post_items(url,items,option);
        return [biz_response,biz_data];
    }
    static search = async (url,search,option)  => {
        const [biz_response,biz_data] = await Service.search(url,search,option);
        return [biz_response,biz_data];
    }
}
