class Data_Logic {
    static get = (table,id,option) => {
        option = !Obj.check_is_empty(option) ? option : {};
        /* options
            - data
            - title
            - parent
            - user
            - generate_id
            - count
            */
        if(Str.check_is_null(table)){
            table = Data_Table.BLANK;
        }
        if(Str.check_is_null(id)){
            id = 0;
        }
        let data = {table:table,id:id};
        if(option.data){
            data = Obj.merge(data,option.data);
        }
        if(option.title){
            data[Data_Field.TITLE] = option.title;
        }
        if(option.parent){
            data[Data_Field.PARENT_TABLE] = option.parent[Data_Field.TABLE];
            data[Data_Field.PARENT_ID] = option.parent[Data_Field.ID];
        }
        if(option.user){
            data[Data_Field.USER_TABLE] = option.user[Data_Field.TABLE];
            data[Data_Field.USER_ID] = option.user[Data_Field.ID];
        }
        if(option.generate_id){
            data[Data_Field.ID] = Num.get_id(999);
        }
        if(option.count){
            let data_items = [];
            if(!data.title){
                data.title = 'Item';
            }
            for(let a = 1; a < option.count+1; a++){
                let copy = { ...data };
                copy.title = data.title + " " + a;
                if(option.generate_id){
                    copy[Data_Field.ID] = Num.get_id(999);
                }
                data_items.push(copy);
            }
            data = data_items;
        }
        return data;
    };
    static get_search = (table,filter,option) => {
        option = !Obj.check_is_empty(option) ? option : {sort_by:{},page_current:1,page_size:0};
        return {table:table,filter:filter,sort_by:option.sort_by?option.sort_by:{},page_current:option.page_current?option.page_current:1,page_size:option.page_size?option.page_size:0};
    };
    static get_join = (value_type,search,option) => {
        option = !Obj.check_is_empty(option)  ? option : {};
        value_type = value_type ? value_type : Data_Value_Type.ITEMS;
        search = search ? search : Data_Logic.get_search(Data_TABLE.BLANK);
        let field = option.field ? option.field : {};
        let distinct = option.distinct ? option.distinct : null; //distinct:{field:'title',sort_by:Data_Type.SEARCH_SORT_BY_DESC}
        let title = option.title ? Str.get_title_url(option.title) : Str.get_lower_case(Str.get_plural(Data_Title.JOIN));
        let foreigns = option.foreigns ? option.foreigns : [];

        search.page_current = !Str.check_is_null(option.page_current) ? option.page_current : search.page_current;
        search.page_size = !Str.check_is_null(option.page_size) ? option.page_size : search.page_size;
        return {value_type:value_type,search:search,field:field,title:title,distinct:distinct,foreigns:foreigns,page_current:search.page_current,page_size:search.page_size};
    }
    static get_foreign = (value_type,foreign_table,foreign_field,parent_field,option) => {
        option = !Obj.check_is_empty(option)  ? option : {};
        value_type = value_type ? value_type : Data_Value_Type.ITEMS;
        foreign_table = foreign_table ? foreign_table : {};
        foreign_field = foreign_field ? foreign_field : Data_Field.PARENT_ID;
        parent_field = parent_field ? parent_field : parent_field;
        let field = option.field ? option.field : null;
        let title = option.title ? Str.get_title_url(option.title) : Str.get_lower_case(Str.get_plural(Data_Title.FOREIGN));
        let page_current = option.page_current ? option.page_current : 1;
        let page_size = option.page_size ? option.page_size : 0;
        let sort_by = option.sort_by ? option.sort_by : {};
        let foreigns = option.foreigns ? option.foreigns : [];
        let not_found = option.not_found ? option.not_found : Data_Logic.get_not_found(foreign_table,0) ;
        return {not_found:not_found,value_type:value_type,sort_by:sort_by,foreign_table:foreign_table,foreign_field:foreign_field,parent_field:parent_field,field:field,title:title,page_current:page_current,page_size:page_size,foreigns:foreigns};
    };
    static get_foreign_parent = (parent_table,option) => {
        option = !Obj.check_is_empty(option)  ? option : {};
        option = Obj.merge(option,{title:'parent'});
        return Data_Logic.get_foreign(Data_Value_Type.ONE,parent_table,Data_Field.ID,Data_Field.PARENT_ID,option);
    };
    static get_message_by_response_field = (response_field) =>{
        switch(response_field){
            case Data_Response_Field.ITEMS_SEARCH_CONFIRM:
                return "Item(s) search success.";
                break;
            case Data_Response_Field.ITEMS_SEARCH_FAIL:
                return "Item(s) search failed.";
                break;
            case Response_Field.GET_CONFIRM:
                return "Item get successfully.";
                break;
            case Response_Field.GET_FAIL:
                return "Item get failed.";
                break;
            case Data_Response_Field.ITEM_COPY_CONFIRM:
                return "Item copied successfully.";
                break;
            case Data_Response_Field.ITEM_COPY_FAIL:
                return "Item copy failed.";
                break;
            case Data_Response_Field.ITEMS_COUNT_CONFIRM:
                return "Item(s)) counted successfully.";
                break;
            case Response_Field.POST_CONFIRM:
                return "Item posted successfully.";
                break;
            case Response_Field.POST_FAIL:
                return "Item posted failed.";
                break;
            case Data_Response_Field.ITEMS_POST_CONFIRM:
                return "Item(s) posted successfully.";
                break;
            case Data_Response_Field.ITEMS_POST_FAIL:
                return "Item(s) posted failed.";
                break;
            case Response_Field.DELETE_CONFIRM:
                return "Item deleted successfully.";
                break;
            case Response_Field.DELETE_FAIL:
                return "Item not deleted.";
                break;
            case Data_Response_Field.ITEMS_DELETE_FAIL:
                return "Item(s) not deleted.";
                break;
            case Data_Response_Field.ITEMS_DELETE_CONFIRM:
                return "Item(s) deleted successfully.";
                break;
            default:
                if(response_field){
                    return response_field;
                }else{
                    return "Error Message Not Availble";
                }
        }
    }
    static copy = (table,item,option)=>{
        let copy_item = Data_Logic.get(table,0);
        option = !Obj.check_is_empty(option)  ? option : {};
        const keys = Object.keys(item);
        keys.forEach(key => {
            if(
                key!=Data_Field.ID&&
                key!=Data_Field.TABLE&&
                key!=Data_Field.SOURCE&&
                key!=Data_Field.DATE_CREATE&&
                key!=Data_Field.DATE_SAVE&&
                key!=Data_Field.OBJ&&
                key!=Data_Field.USER&&
                key!=Data_Field.GROUP&&
                key!=Data_Field.ITEM&&
                !Obj.check_is_array(item[key])&&
                Obj.check_is_value(item[key])
            )
            {
                copy_item[key]=item[key];
            }
        });
        return copy_item;
    };
    static get_not_found = (table,id,option) =>{
        option=!Obj.check_is_empty(option)?option:{};
        if(!table){
            table = Data_Table.BLANK;
        }
        if(!id){
            id = 0;
        }
        let item = Data_Logic.get(table,id);
        item.id = 0;
        item.id_key = id;
        item.title = "Not Found";
        item.source = Data_Title.SOURCE_NOT_FOUND;
        return item;
    };
    static get_table_by_name = (table,option) =>{
        table = table?table:"";
        let table_title = "";
        option = option ? option : {lowercase:false,plural:false,url:false};
        table_title = String(Str.get_title(table.replaceAll('_',' ').replace('biz',''))).trim();
        if(option.plural){
            table_title = table_title + 's';
        }
        if(option.lowercase){
            table_title = table_title.toLowerCase();
        }
        if(option.url){
            table_title = table_title.replace(" ","_").toLowerCase();
        }
        return table_title;
    };
    static get_test_cost = () =>{
        return String(Str.get_id(999)) + "." + String(Str.get_id(99));
    }
    static get_test_parents = (count,option) =>{
        if(!count){
            count = 9;
        }
        let parents = [];
        for(let a = 0; a < count; a++){
            parents.push(Data_Logic.get_test_parent(option));
        }
        return parents;
    };
    static get_test_parent = (option) =>{
        option = !Obj.check_is_empty(option) ? option : {title:'Product '+Str.get_id(999)};
        let data = Data_Logic.get(Table.PRODUCT,0,option);
        data.cost = Data_Logic.get_test_cost();
        data.old_cost = Data_Logic.get_test_cost();
        data.category = "Category "+String(Str.get_id());
        data.type = "Type "+String(Str.get_id());
        data.sub_type = "Sub Type "+String(Str.get_id());
        data.stock = String(Str.get_id(3-1));
        data.tag = "Tag "+ Str.get_id() + ", Tag "+Str.get_id() + ", Tag "+ Str.get_id();
        return data;
    };
}
class Storage_Logic {
    static post = (key,value,option) => {
        option = !Obj.check_is_empty(option) ? option : {};
        if(!key){
            key = '';
        }
        key = Str.get_title_url(key);
        if(option.time_limit){
            Memory_Logic.post(key+Data_Field.TIME,dayjs().add(option.time_limit,Data_Field.MINUTE));
            Memory_Logic.post(key+Data_Field.DATA,value);
        }else{
            Memory_Logic.post(key,value);
        }
    }
    static delete_all = () => {
        Memory_Logic.delete_all();
    }
    static delete = (key) => {
        if(!key){
            key = '';
        }
        key = Str.get_title_url(key);
        Memory_Logic.delete(key);
        Memory_Logic.delete(key+Data_Field.TIME);
        Memory_Logic.delete(key+Data_Field.TIME);
    }
    static get = (key,option) => {
        option = !Obj.check_is_empty(option) ? option : {};
        if(!key){
            key = '';
        }
        key = Str.get_title_url(key);
        if(option.time_limit){
            let time = Memory_Logic.get(key+Data_Field.TIME);
            if(dayjs(time).isValid() && dayjs().isBefore(dayjs(time).add(option.time_limit))){
                return Memory_Logic.get(key+Data_Field.DATA);
            }else{
                return null;
            }
        }else{
            return Memory_Logic.get(key);
        }
    }
}

